		tcp dport { 22, 80, 111, 443, 2379-2380, 6080, 6443, 9001, 9099-9100, 9103-9105, 9107-9108, 9192, 9258, 9637, 9978-9980, 10250, 10256-10259, 17697, 22623-22624, 30000-60999 } accept
		udp dport { 111, 30000-60999 } accept
		tcp dport 9000-9999 accept
		udp dport 9000-9999 accept
		tcp dport 30000-32767 accept
		udp dport 30000-32767 accept
		tcp dport 10180 accept
		udp dport 10180 accept
		tcp dport 80 accept
		udp dport 80 accept
		log prefix "firewall " drop
	}
}
